"""
main.py — 서울 급매 파싱 웹앱 빌드 스크립트
실행하면 3개 파일을 자동 생성합니다:
  - index.html
  - .github/workflows/update.yml  (매일 자정 KST 재빌드)
  - requirements.txt

GitHub Secrets 3개: SUPABASE_URL / SUPABASE_ANON_KEY / MOLIT_API_KEY
"""

import os, pathlib

ROOT = pathlib.Path(__file__).parent

INDEX_HTML = '<!DOCTYPE html>\n    <html lang="ko">\n    <head>\n        <meta charset="UTF-8">\n        <title>부동산 폭등 폭락 시그널 추적기</title>\n        <script src="https://cdn.jsdelivr.net/npm/@supabase/supabase-js"></script>\n        <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>\n        <script src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js"></script>\n        <style>\n            :root { --blue: #3b82f6; --red: #ef4444; --dark: #0f172a; --gray: #f8fafc; }\n            body { font-family: \'Pretendard\', -apple-system, sans-serif; background: var(--gray); margin: 0; padding: 20px; color: var(--dark); }\n            .container { max-width: 1200px; margin: 0 auto; }\n            .header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 30px; }\n            .download-group { display: flex; gap: 10px; }\n            .btn-download { background: #10b981; color: white; border: none; padding: 10px 20px; border-radius: 8px; cursor: pointer; font-weight: bold; font-size: 0.9rem; transition: 0.2s; }\n            .btn-download:hover { background: #059669; }\n            .filter-panel { background: white; padding: 20px; border-radius: 20px; box-shadow: 0 4px 15px rgba(0,0,0,0.05); margin-bottom: 25px; display: flex; gap: 40px; }\n            .btn-group button { background: #f1f5f9; border: none; padding: 10px 18px; border-radius: 12px; cursor: pointer; font-weight: 600; font-size: 0.85rem; transition: 0.2s; }\n            .btn-group button.active { background: var(--dark); color: white; }\n            .chart-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(350px, 1fr)); gap: 20px; margin-bottom: 30px; }\n            .chart-card { background: white; padding: 25px; border-radius: 24px; box-shadow: 0 4px 20px rgba(0,0,0,0.04); position: relative; min-height: 280px; }\n            .chart-card h3 { margin-top: 0; display: flex; justify-content: space-between; align-items: center; }\n            .reset-loc { font-size: 0.7rem; color: var(--blue); cursor: pointer; border: 1px solid var(--blue); padding: 2px 8px; border-radius: 4px; display: none; }\n            .list-panel { background: white; padding: 30px; border-radius: 28px; box-shadow: 0 10px 40px rgba(0,0,0,0.03); }\n            .tabs { display: flex; gap: 20px; margin-bottom: 25px; border-bottom: 2px solid #f1f5f9; }\n            .tab-btn { font-size: 1.4rem; border: none; background: none; cursor: pointer; color: #cbd5e1; font-weight: 800; padding-bottom: 15px; }\n            .tab-btn.active.down { color: var(--blue); border-bottom: 4px solid var(--blue); }\n            .tab-btn.active.up { color: var(--red); border-bottom: 4px solid var(--red); }\n            table { width: 100%; border-collapse: collapse; }\n            th { text-align: left; padding: 15px; color: #94a3b8; font-size: 0.85rem; }\n            td { padding: 20px 15px; border-bottom: 1px solid #f8fafc; }\n            .price-tag { font-weight: 800; font-size: 1.1rem; }\n            .drop { color: var(--blue); }\n            .rise { color: var(--red); }\n            .btn-map { background: #fee500; border: none; padding: 8px 15px; border-radius: 10px; font-weight: bold; cursor: pointer; }\n            .filter-info { background: #e0f2fe; color: #0369a1; padding: 10px 20px; border-radius: 10px; margin-bottom: 15px; display: none; font-weight: bold; }\n        </style>\n    </head>\n    <body>\n        <div class="container">\n            <div class="header">\n                <h1 style="font-size: 1.8rem; letter-spacing: -1px;">📡 부동산 폭등 폭락 시그널 <span style="color:#64748b; font-weight:400;">양극단 추적기</span></h1>\n                <div class="download-group">\n                    <button class="btn-download" onclick="downloadExcel()">📊 Excel 시트 저장</button>\n                </div>\n            </div>\n            <div class="filter-panel">\n                <div class="filter-group"><label style="display:block; font-size:0.8rem; font-weight:bold; color:#64748b; margin-bottom:10px;">📅 거래 기간</label>\n                    <div class="btn-group">\n                        <button class="active" onclick="setFilter(\'period\', 0, this)">전체</button>\n                        <button onclick="setFilter(\'period\', 6, this)">6개월</button>\n                        <button onclick="setFilter(\'period\', 12, this)">1년</button>\n                        <button onclick="setFilter(\'period\', 24, this)">2년</button>\n                    </div>\n                </div>\n                <div class="filter-group"><label style="display:block; font-size:0.8rem; font-weight:bold; color:#64748b; margin-bottom:10px;">💰 변동 금액</label>\n                    <div class="btn-group">\n                        <button class="active" onclick="setFilter(\'price\', 0, this)">전체</button>\n                        <button onclick="setFilter(\'price\', 10000, this)">1억↑</button>\n                        <button onclick="setFilter(\'price\', 30000, this)">3억↑</button>\n                        <button onclick="setFilter(\'price\', 50000, this)">5억↑</button>\n                    </div>\n                </div>\n            </div>\n            <div class="chart-grid">\n                <div class="chart-card"><h3>📈 시장 심리</h3><canvas id="ratioChart"></canvas></div>\n                <div class="chart-card" style="grid-column:1/-1; min-height:420px;">\n                    <h3>📍 지역별 빈도 <span id="resetLoc" class="reset-loc" onclick="resetLocFilter()">해제</span></h3>\n                    <p style="font-size:0.95rem; color:#475569; margin-top:-10px; font-weight:500;">* 막대를 클릭하면 해당 지역만 필터링됩니다.</p>\n                    <canvas id="locChart" height="160"></canvas>\n                </div>\n                <div class="chart-card"><h3>🏆 변동 TOP 10</h3><canvas id="topChart"></canvas></div>\n                <!-- 추가 지표 행 -->\n                <div class="chart-card" style="grid-column: 1/-1;">\n                    <h3>📅 월별 폭락/폭등 건수 추이</h3>\n                    <canvas id="monthlyChart" height="80"></canvas>\n                </div>\n                <div class="chart-card">\n                    <h3>📉 지역별 평균 낙폭률 (%)</h3>\n                    <canvas id="dropRateChart"></canvas>\n                </div>\n                <div class="chart-card">\n                    <h3>🗺 지역별 낙폭 강도 (평균 억)</h3>\n                    <canvas id="heatChart"></canvas>\n                </div>\n            </div>\n            <div class="list-panel">\n                <div id="filter-status" class="filter-info"></div>\n                <div class="tabs">\n                    <button class="tab-btn active down" onclick="setMode(\'down\', this)">📉 하락 시그널</button>\n                    <button class="tab-btn up" onclick="setMode(\'up\', this)">🔥 상승 시그널</button>\n                </div>\n                <table id="main-table">\n                    <thead><tr><th>거래일</th><th>지역/단지명</th><th>실거래가</th><th>변동액</th><th>액션</th></tr></thead>\n                    <tbody id="list"></tbody>\n                </table>\n            </div>\n        </div>\n        <script>\n            const client = supabase.createClient(\n                "%%SUPABASE_URL%%",\n                "%%SUPABASE_ANON_KEY%%"\n            );\n            let rawData = []; let currentMode = \'down\'; let filters = { period: 0, price: 0, loc: null }; let charts = {};\n\n            async function init() {\n                // 페이지네이션으로 전체 데이터 로드\n                let all = [];\n                let page = 0;\n                const PAGE = 1000;\n                while (true) {\n                    const { data, error } = await client\n                        .from(\'drop_results\')\n                        .select(\'*\')\n                        .order(\'listed_at\', { ascending: false })\n                        .range(page * PAGE, (page + 1) * PAGE - 1);\n                    if (error || !data || data.length === 0) break;\n                    all = all.concat(data);\n                    if (data.length < PAGE) break;\n                    page++;\n                }\n                // drop_amount 없으면 current_price - trade_price로 계산\n                rawData = all.map(r => {\n                    if (r.drop_amount == null && r.trade_price && r.current_price) {\n                        r.drop_amount = r.current_price - r.trade_price;\n                    }\n                    return r;\n                }).filter(r => r.drop_amount != null && r.drop_amount !== 0);\n\n                render();\n            }\n\n            function setFilter(type, val, btn) {\n                filters[type] = val;\n                btn.parentElement.querySelectorAll(\'button\').forEach(b => b.classList.remove(\'active\'));\n                btn.classList.add(\'active\'); render();\n            }\n            function setMode(m, btn) {\n                currentMode = m;\n                document.querySelectorAll(\'.tab-btn\').forEach(b => b.classList.remove(\'active\'));\n                btn.classList.add(\'active\'); render();\n            }\n            function resetLocFilter() {\n                filters.loc = null;\n                document.getElementById(\'resetLoc\').style.display = \'none\';\n                render();\n            }\n\n            function isDown(i) {\n                // trade_price 있으면: 현재가 < 기준가 = 하락(급매)\n                if (i.trade_price != null && i.trade_price > 0) return i.current_price < i.trade_price;\n                // trade_price 없으면: 기존 폭락앱 방식 (음수 = 하락)\n                return i.drop_amount < 0;\n            }\n            function isUp(i) {\n                // trade_price 있으면: 현재가 > 기준가 = 상승\n                if (i.trade_price != null && i.trade_price > 0) return i.current_price > i.trade_price;\n                // trade_price 없으면: 기존 폭락앱 방식 (양수 = 상승)\n                return i.drop_amount > 0;\n            }\n            function getFilteredData() {\n                let filtered = rawData.filter(i => currentMode === \'up\' ? isUp(i) : isDown(i));\n                if (filters.loc) filtered = filtered.filter(i => i.loc_name === filters.loc);\n                if (filters.period > 0) {\n                    const cutoff = new Date();\n                    cutoff.setMonth(cutoff.getMonth() - filters.period);\n                    // listed_at 기준으로 필터\n                    filtered = filtered.filter(i => getDate(i) && new Date(getDate(i)) >= cutoff);\n                }\n                if (filters.price > 0) filtered = filtered.filter(i => Math.abs(i.drop_amount) >= filters.price);\n                return filtered.sort((a, b) => currentMode === \'up\' ? b.drop_amount - a.drop_amount : a.drop_amount - b.drop_amount);\n            }\n\n            function fmtDate(val) {\n                if (!val) return \'-\';\n                return String(val).slice(0, 10);\n            }\n            function getDate(row) {\n                return row.listed_at || row.deal_date || null;\n            }\n\n            function render() {\n                const data = getFilteredData();\n                updateCharts(data);\n                const status = document.getElementById(\'filter-status\');\n                if (filters.loc) { status.style.display = \'block\'; status.innerText = `📍 ${filters.loc} 시그널만 표시 중`; }\n                else { status.style.display = \'none\'; }\n                document.getElementById(\'list\').innerHTML = data.map(i => `\n                    <tr>\n                        <td style="color:#94a3b8; font-size:0.85rem;">${fmtDate(getDate(i))}</td>\n                        <td>\n                            <div style="font-size:0.75rem; color:#64748b;">${i.loc_name}</div>\n                            <div style="font-weight:bold; font-size:1rem; cursor:pointer;"\n                                 onclick="window.open(\'https://search.naver.com/search.naver?query=${encodeURIComponent(i.loc_name + \' \' + i.apt_name)}\', \'_blank\')">\n                                ${i.apt_name}\n                            </div>\n                        </td>\n                        <td class="price-tag">${(i.current_price / 10000).toFixed(1)}억</td>\n                        <td class="price-tag ${currentMode === \'up\' ? \'rise\' : \'drop\'}">\n                            ${isDown(i) ? \'▼\' : \'▲\'} ${(Math.abs(i.drop_amount) / 10000).toFixed(1)}억\n                        </td>\n                        <td><button class="btn-map"\n                            onclick="window.open(\'https://map.kakao.com/?q=${encodeURIComponent(i.loc_name + \' \' + i.apt_name)}\', \'_blank\')">MAP</button></td>\n                    </tr>\n                `).join(\'\');\n            }\n\n            function downloadExcel() {\n                const data = getFilteredData().map(i => ({\n                    "거래일": fmtDate(getDate(i)),\n                    "지역": i.loc_name,\n                    "단지명": i.apt_name,\n                    "실거래가(억)": (i.current_price / 10000).toFixed(2),\n                    "변동액(억)": (i.drop_amount / 10000).toFixed(2)\n                }));\n                const ws = XLSX.utils.json_to_sheet(data);\n                const wb = XLSX.utils.book_new();\n                XLSX.utils.book_append_sheet(wb, ws, "시그널_리스트");\n                XLSX.writeFile(wb, `부동산_시그널_${currentMode}_${new Date().toISOString().slice(0,10)}.xlsx`);\n            }\n\n            function updateCharts(data) {\n                const ups = rawData.filter(i => isUp(i)).length;\n                const downs = rawData.filter(i => isDown(i)).length;\n                if (charts.ratio) charts.ratio.destroy();\n                charts.ratio = new Chart(document.getElementById(\'ratioChart\'), {\n                    type: \'doughnut\',\n                    data: { labels: [\'상승\', \'하락\'], datasets: [{ data: [ups, downs], backgroundColor: [\'#ef4444\', \'#3b82f6\'], borderWidth: 0 }] },\n                    options: { cutout: \'75%\' }\n                });\n                const locCounts = {};\n                rawData.filter(i => currentMode === \'up\' ? isUp(i) : isDown(i))\n                       .forEach(i => locCounts[i.loc_name] = (locCounts[i.loc_name] || 0) + 1);\n                if (charts.loc) charts.loc.destroy();\n                charts.loc = new Chart(document.getElementById(\'locChart\'), {\n                    type: \'bar\',\n                    data: { labels: Object.keys(locCounts), datasets: [{ label: \'시그널 건수\', data: Object.values(locCounts), backgroundColor: \'#1e293b\', borderRadius: 8 }] },\n                    options: {\n                        onClick: (e, el) => {\n                            if (el.length > 0) {\n                                filters.loc = Object.keys(locCounts)[el[0].index];\n                                document.getElementById(\'resetLoc\').style.display = \'inline-block\';\n                                render();\n                            }\n                        },\n                        plugins: { legend: { display: false } },\n                        layout: { padding: { bottom: 20 } },\n                        scales: {\n                            x: {\n                                ticks: {\n                                    maxRotation: 90,\n                                    minRotation: 90,\n                                    font: { size: 11, weight: \'bold\' },\n                                    autoSkip: false,\n                                    padding: 5\n                                },\n                                grid: { display: false }\n                            },\n                            y: { beginAtZero: true }\n                        }\n                    }\n                });\n                // 단지명 중복 제거 후 TOP10\n                const seen = new Set();\n                const sorted = [...data]\n                    .sort((a, b) => Math.abs(b.drop_amount) - Math.abs(a.drop_amount))\n                    .filter(i => { if (seen.has(i.apt_name)) return false; seen.add(i.apt_name); return true; })\n                    .slice(0, 10);\n                if (charts.top) charts.top.destroy();\n                charts.top = new Chart(document.getElementById(\'topChart\'), {\n                    type: \'bar\',\n                    options: { indexAxis: \'y\', plugins: { legend: { display: false } } },\n                    data: {\n                        labels: sorted.map(i => i.apt_name.substring(0, 6)),\n                        datasets: [{ label: \'억\', data: sorted.map(i => Math.abs(i.drop_amount) / 10000), backgroundColor: \'#64748b\' }]\n                    }\n                });\n\n                // 4. 월별 폭락/폭등 추이\n                const monthDown = {}, monthUp = {};\n                rawData.forEach(i => {\n                    const m = fmtDate(i.listed_at).slice(0,7);\n                    if (!m || m === \'-\') return;\n                    if (isDown(i)) monthDown[m] = (monthDown[m]||0) + 1;\n                    else if (isUp(i)) monthUp[m] = (monthUp[m]||0) + 1;\n                });\n                const allMonths = [...new Set([...Object.keys(monthDown), ...Object.keys(monthUp)])].sort();\n                if (charts.monthly) charts.monthly.destroy();\n                charts.monthly = new Chart(document.getElementById(\'monthlyChart\'), {\n                    type: \'bar\',\n                    data: {\n                        labels: allMonths,\n                        datasets: [\n                            { label: \'📉 폭락\', data: allMonths.map(m => monthDown[m]||0), backgroundColor: \'#3b82f6\', borderRadius: 4 },\n                            { label: \'🔥 폭등\', data: allMonths.map(m => monthUp[m]||0), backgroundColor: \'#ef4444\', borderRadius: 4 }\n                        ]\n                    },\n                    options: { plugins: { legend: { position: \'top\' } }, scales: { x: { stacked: false }, y: { beginAtZero: true } } }\n                });\n\n                // 5. 지역별 평균 낙폭률\n                const locRate = {};\n                rawData.filter(i => isDown(i) && i.current_price > 0).forEach(i => {\n                    if (!locRate[i.loc_name]) locRate[i.loc_name] = { sum: 0, cnt: 0 };\n                    locRate[i.loc_name].sum += Math.abs(i.drop_amount) / i.current_price * 100;\n                    locRate[i.loc_name].cnt++;\n                });\n                const locRateLabels = Object.keys(locRate).sort((a,b) => locRate[b].sum/locRate[b].cnt - locRate[a].sum/locRate[a].cnt);\n                const locRateData = locRateLabels.map(k => +(locRate[k].sum/locRate[k].cnt).toFixed(1));\n                if (charts.dropRate) charts.dropRate.destroy();\n                charts.dropRate = new Chart(document.getElementById(\'dropRateChart\'), {\n                    type: \'bar\',\n                    data: { labels: locRateLabels, datasets: [{ label: \'평균 낙폭률(%)\', data: locRateData, backgroundColor: locRateData.map(v => v > 15 ? \'#ef4444\' : v > 10 ? \'#f97316\' : \'#3b82f6\'), borderRadius: 6 }] },\n                    options: { indexAxis: \'y\', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true } } }\n                });\n\n                // 6. 지역별 낙폭 강도 (평균 억)\n                const locAmt = {};\n                rawData.filter(i => isDown(i)).forEach(i => {\n                    if (!locAmt[i.loc_name]) locAmt[i.loc_name] = { sum: 0, cnt: 0 };\n                    locAmt[i.loc_name].sum += Math.abs(i.drop_amount);\n                    locAmt[i.loc_name].cnt++;\n                });\n                const locAmtLabels = Object.keys(locAmt).sort((a,b) => locAmt[b].sum/locAmt[b].cnt - locAmt[a].sum/locAmt[a].cnt);\n                const locAmtData = locAmtLabels.map(k => +(locAmt[k].sum/locAmt[k].cnt/10000).toFixed(1));\n                const maxAmt = Math.max(...locAmtData);\n                if (charts.heat) charts.heat.destroy();\n                charts.heat = new Chart(document.getElementById(\'heatChart\'), {\n                    type: \'bar\',\n                    data: { labels: locAmtLabels, datasets: [{ label: \'평균 낙폭(억)\', data: locAmtData, backgroundColor: locAmtData.map(v => `rgba(239,68,68,${(v/maxAmt*0.8+0.2).toFixed(2)})`), borderRadius: 6 }] },\n                    options: { indexAxis: \'y\', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true } } }\n                });\n            }\n            init();\n        </script>\n    </body>\n    </html>'

GITHUB_WORKFLOW = """name: Daily Rebuild

on:
  schedule:
    - cron: '0 15 * * *'   # 매일 자정 KST
  workflow_dispatch:

permissions:
  contents: write

jobs:
  build:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - uses: actions/setup-python@v5
        with:
          python-version: '3.11'

      - name: Install dependencies
        run: pip install -r requirements.txt

      - name: 1. 데이터 수집
        env:
          SUPABASE_URL:      ${{ secrets.SUPABASE_URL }}
          SUPABASE_ANON_KEY: ${{ secrets.SUPABASE_ANON_KEY }}
          MOLIT_API_KEY:     ${{ secrets.MOLIT_API_KEY }}
        run: python collect.py

      - name: 2. index.html 재빌드
        run: python main.py

      - name: 3. 커밋 & 푸시
        run: |
          git config user.name  "github-actions[bot]"
          git config user.email "github-actions[bot]@users.noreply.github.com"
          git add index.html
          git diff --cached --quiet || git commit -m "chore: daily rebuild $(date +'%Y-%m-%d')"
          git push
"""

REQUIREMENTS = """requests>=2.31.0
supabase>=2.0.0
python-dotenv>=1.0.0
"""


def inject_env(html):
    return (html
        .replace("%%SUPABASE_URL%%",      "https://ofbtvvzpvuezfdirwhtd.supabase.co")
        .replace("%%SUPABASE_ANON_KEY%%", "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9mYnR2dnpwdnVlemZkaXJ3aHRkIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzcwMjY1MTYsImV4cCI6MjA5MjYwMjUxNn0.OLCpaSiQxs37dZC3P0QXxOTp4OKRYYApaF34b2UkOlA")
        .replace("%%MOLIT_API_KEY%%",     "7b6efd99b84e03fca06677a5f9632db682bac3e47d90f5ec37f3b4947e84307e")
    )


def main():
    (ROOT / "index.html").write_text(inject_env(INDEX_HTML), encoding="utf-8")
    print("✅  index.html 생성 완료")

    wf = ROOT / ".github" / "workflows"
    wf.mkdir(parents=True, exist_ok=True)
    (wf / "update.yml").write_text(GITHUB_WORKFLOW, encoding="utf-8")
    print("✅  .github/workflows/update.yml 생성 완료")

    (ROOT / "requirements.txt").write_text(REQUIREMENTS, encoding="utf-8")
    print("✅  requirements.txt 생성 완료")

    print()
    print("━" * 50)
    print("🔐  GitHub Secrets 등록 필요:")
    print("   SUPABASE_URL / SUPABASE_ANON_KEY / MOLIT_API_KEY")
    print("━" * 50)


if __name__ == "__main__":
    main()
